from openai import OpenAI
client = OpenAI()

response = client.chat.completions.create(
    model='gpt-4o-mini',
    messages=[
        {
            'role': 'system',
            'content': 'Classify the support ticket into exactly one category: '
                       'billing, technical, or other. '
                       'Reply with only the category label, nothing else.',
        },
        {
            'role': 'user',
            'content': 'My invoice shows a charge I did not authorise.',
        },
    ],
    max_tokens=10,
    temperature=0,
)
print(response.choices[0].message.content)  # 'billing'
